import React from "react";
import Carousel from "react-bootstrap/Carousel";

const BASE_PATH = '/LUAD-ESA-Database';

function CarouselComponent() {
  // 定义轮播图数据，方便维护
  // 路径直接指向 public 根目录下的图片文件
  const slides = [
    { src: BASE_PATH + '/DEGs.png', alt: "DEGs Analysis", label: "Differentially Expressed Genes" },
    { src: BASE_PATH + '/Survival.png', alt: "Survival Analysis", label: "Survival Analysis (Cox)" },
    { src: BASE_PATH + '/Download.png', alt: "Download Center", label: "Data Download Center" },
    { src: BASE_PATH + '/Help.png', alt: "User Help", label: "Database Documentation" },
  ];

  return (
    // 添加 interval={3000} 实现自动播放（可选，面试推荐）
    <Carousel interval={1500} fade>
      {slides.map((slide, index) => (
        <Carousel.Item key={index}>
          {/* 这里是核心修改部分 */}
          <div
            style={{
              height: "500px", // 保持你原来的高度，或根据图片比例调整
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: "#000", // 图片未加载出时的背景色，防止闪烁
              // overflow: "hidden" // 裁剪超出部分
            }}
          >
            <img
              src={slide.src}
              alt={slide.alt}
              style={{
                width: "100%",    // 宽度撑满容器
                height: "100%",   // 高度撑满容器
                objectFit: "cover", // 核心！保持比例缩放，并填充整个容器（超出会被裁剪），防止图片变形
                objectPosition: "center" // 图片居中显示
              }}
            />
          </div>
          
          {/* 可选：为图片添加文字说明 */}
          <Carousel.Caption>
            <h3 style={{ textShadow: "1px 1px 2px rgba(0,0,0,0.8)" }}>{slide.label}</h3>
          </Carousel.Caption>
        </Carousel.Item>
      ))}
    </Carousel>
  );
}

export default CarouselComponent;