import React, { useEffect, useState } from 'react';
import { Table, Card, Typography, Input, Space, Tag, Empty } from 'antd';
import Papa from 'papaparse';

const { Title, Text } = Typography;
const { Search } = Input;
const BASE_PATH = '/LUAD-ESA-Database';

export default function DEGs() {
  const [rawData, setRawData] = useState([]); // 存储原始数据
  const [filteredData, setFilteredData] = useState([]); // 存储搜索后的数据
  const [columns, setColumns] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    
    fetch(BASE_PATH + '/DEGs.csv')
      .then((response) => response.text())
      .then((csvText) => {
        Papa.parse(csvText, {
          header: true,
          skipEmptyLines: true,
          complete: (results) => {
            if (results.data.length > 0) {
              const fields = Object.keys(results.data[0]);
              
              // 动态生成列配置
              const tableColumns = fields.map((field) => {
                const baseColumn = {
                  title: field,
                  dataIndex: field,
                  key: field,
                  sorter: (a, b) => {
                    const valA = a[field];
                    const valB = b[field];
                    return isNaN(valA) ? (valA || '').localeCompare(valB || '') : valA - valB;
                  },
                };

                // 1. 处理 Gene ID 跳转链接 (假设列名是 'Gene_ID' 或 'ID')
                if (field.toLowerCase().includes('id')) {
                  return {
                    ...baseColumn,
                    render: (text) => (
                      <a 
                        href={`https://www.ensembl.org/id/${text}`} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        style={{ fontWeight: 'bold', color: '#1890ff' }}
                      >
                        {text}
                      </a>
                    ),
                  };
                }

                // 2. 对 LogFC 进行色彩高亮处理 (可选，增加专业性)
                if (field.toLowerCase().includes('logfc')) {
                    return {
                        ...baseColumn,
                        render: (val) => (
                            <Text type={val > 0 ? 'danger' : 'success'}>{val}</Text>
                        )
                    }
                }

                return baseColumn;
              });

              const dataWithKeys = results.data.map((row, index) => ({
                ...row,
                key: index,
              }));

              setColumns(tableColumns);
              setRawData(dataWithKeys);
              setFilteredData(dataWithKeys);
            }
            setLoading(false);
          },
        });
      })
      .catch((err) => {
        console.error("Error:", err);
        setLoading(false);
      });
  }, []);

  // 3. 搜索逻辑
  const onSearch = (value) => {
    const currValue = value.toLowerCase();
    const filtered = rawData.filter(entry => {
      // 假设你的列名分别是 Gene_ID 和 Gene_Name
      // 如果列名不同，请根据实际情况修改 key 值
      return (
        entry.Gene_ID?.toLowerCase().includes(currValue) || 
        entry.Gene_Name?.toLowerCase().includes(currValue)
      );
    });
    setFilteredData(filtered);
  };

  return (
    <div style={{ padding: '40px', background: '#f5f7fa', minHeight: '90vh' }}>
      <Card bordered={false} style={{ borderRadius: '12px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }}>
        <Space direction="vertical" size="large" style={{ width: '100%' }}>
          
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Title level={3} style={{ margin: 0 }}>Differentially Expressed Genes List</Title>
            {/* 搜索框 */}
            <Search
              placeholder="Search by Gene ID or Gene Name (e.g. ENSG... or TP53)"
              allowClear
              enterButton="Search"
              size="large"
              onSearch={onSearch}
              onChange={(e) => !e.target.value && setFilteredData(rawData)} // 清空时自动恢复
              style={{ width: 450 }}
            />
          </div>

          <Table 
            dataSource={filteredData} 
            columns={columns} 
            loading={loading}
            bordered
            pagination={{ 
                pageSize: 10, 
                showSizeChanger: true,
                showTotal: (total) => `Total ${total} genes` 
            }}
            scroll={{ x: 'max-content' }}
            locale={{ emptyText: <Empty description="No data found" /> }}
          />
        </Space>
      </Card>
    </div>
  );
}